+// =============================================================================
+// Policy Load tests
+// =============================================================================
+
+func TestLoad(t *testing.T) {
+	t.Parallel()
+
+	t.Run("valid YAML", func(t *testing.T) {
+		t.Parallel()
+		dir := t.TempDir()
+		path := filepath.Join(dir, "policy.yaml")
+		content := `version: 1
+blocked:
+  - pattern: "rm -rf /"
+    reason: "dangerous"
+allowed:
+  - pattern: "git status"
+    reason: "safe"
+approval_required:
+  - pattern: "force_release"
+    reason: "needs approval"
+    slb: true
+automation:
+  auto_push: false
+  auto_commit: true
+  force_release: "approval"
+`
+		os.WriteFile(path, []byte(content), 0644)
+		p, err := Load(path)
+		if err != nil {
+			t.Fatalf("Load: %v", err)
+		}
+		if len(p.Blocked) != 1 {
+			t.Errorf("expected 1 blocked rule, got %d", len(p.Blocked))
+		}
+		if len(p.Allowed) != 1 {
+			t.Errorf("expected 1 allowed rule, got %d", len(p.Allowed))
+		}
+		if !p.ApprovalRequired[0].SLB {
+			t.Error("expected SLB flag on approval_required rule")
+		}
+	})
+
+	t.Run("invalid regex", func(t *testing.T) {
+		t.Parallel()
+		dir := t.TempDir()
+		path := filepath.Join(dir, "policy.yaml")
+		content := `version: 1
+blocked:
+  - pattern: "[invalid"
+    reason: "bad regex"
+`
+		os.WriteFile(path, []byte(content), 0644)
+		_, err := Load(path)
+		if err == nil {
+			t.Error("expected error for invalid regex pattern")
+		}
+	})
+
+	t.Run("nonexistent file", func(t *testing.T) {
+		t.Parallel()
+		_, err := Load("/nonexistent/path/policy.yaml")
+		if err == nil {
+			t.Error("expected error for nonexistent file")
+		}
+	})
+
+	t.Run("invalid YAML", func(t *testing.T) {
+		t.Parallel()
+		dir := t.TempDir()
+		path := filepath.Join(dir, "policy.yaml")
+		os.WriteFile(path, []byte("{{{{not yaml"), 0644)
+		_, err := Load(path)
+		if err == nil {
+			t.Error("expected error for invalid YAML")
+		}
+	})
+}
